				&lt;td style=&quot;text-align: center;&quot;&gt;Barbaric&lt;/td&gt;
				&lt;td style=&quot;text-align: center;&quot;&gt;having a bizarre, primitive, or unsophisticated quality&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;&quot;&gt;
				&lt;td style=&quot;text-align: center;&quot;&gt;Famished&lt;/td&gt;
				&lt;td style=&quot;text-align: center;&quot;&gt;intensely hungry&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;&quot;&gt;
				&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;Counterfeit&amp;nbsp;&lt;/td&gt;
				&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;to imitate or feign especially with intent to deceive also&amp;nbsp;&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span id=&quot;docs-internal-guid-0bf84d85-7fff-12f0-36a4-d911daaa7bdd&quot; style=&quot;&quot;&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;border: none; display: inline-block; overflow: hidden; width: 120px; height: 40px;&quot;&gt;&lt;img height=&quot;40&quot; src=&quot;https://lh3.googleusercontent.com/sWn1oC6mlNsROP-zVXMvAlT_Fqes0HlQMQeDtmr94LuJqLv7dOdQtJ2Q7iQ1JS5REaHqKFCFChrBmdKT4svOFMwg4y1JdWWC5pg4X0ls_aEdE-_EV4rBZGTOua1aQGpEgOl5QU9H&quot; style=&quot;margin-left: 0px; margin-top: 0px;&quot; width=&quot;120&quot; /&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;Its&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;first known use&lt;/span&gt;&amp;nbsp;was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;before&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;15th century&lt;/span&gt;.&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Examples&lt;/span&gt;&amp;nbsp;of &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Exorbitant&lt;/span&gt;&amp;#39; in a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;sentence&lt;/span&gt;&lt;/u&gt;:
	&lt;ul style=&quot;&quot;&gt;
		&lt;li style=&quot;&quot;&gt;&lt;em&gt;Critics point out that the cost of the journey is &lt;strong&gt;exorbitant&lt;/strong&gt;&lt;/em&gt;.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;em&gt;Gone should be the days of clients at large firms paying &lt;strong&gt;exorbitant&lt;/strong&gt; fees for what amounts to training for highly paid junior associates.&lt;/em&gt;&lt;/li&gt;
	&lt;/ul&gt;
